import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './AdminPage.css';

function AdminPage() {
  const { token } = useAuth();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [stats, setStats] = useState({});
  const [users, setUsers] = useState([]);
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  
  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'dashboard') {
        const statsRes = await axios.get('http://localhost:5001/api/admin/stats', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStats(statsRes.data);
      } else if (activeTab === 'users') {
        const usersRes = await axios.get('http://localhost:5001/api/admin/users', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setUsers(usersRes.data);
      } else if (activeTab === 'properties') {
        const propsRes = await axios.get('http://localhost:5001/api/admin/properties', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setProperties(propsRes.data);
      }
    } catch (error) {
      console.error('Error fetching admin data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await axios.put(`http://localhost:5001/api/admin/properties/${id}/approve`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchData();
    } catch (error) {
      console.error('Error approving property:', error);
    }
  };

  const handleReject = async (id) => {
    const reason = prompt('Укажите причину отклонения:');
    if (reason) {
      try {
        await axios.put(`http://localhost:5001/api/admin/properties/${id}/reject`, { reason }, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error rejecting property:', error);
      }
    }
  };

  const handleBlockUser = async (id, isBlocked) => {
    try {
      await axios.put(`http://localhost:5001/api/admin/users/${id}/block`, { is_blocked: !isBlocked }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchData();
    } catch (error) {
      console.error('Error blocking user:', error);
    }
  };

  const handleDeleteProperty = async (id) => {
    if (window.confirm('Вы уверены, что хотите удалить это объявление?')) {
      try {
        await axios.delete(`http://localhost:5001/api/admin/properties/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting property:', error);
      }
    }
  };

  return (
    <div className="admin-page">
      <h1>Панель администратора</h1>
      
      <div className="admin-tabs">
        <button className={activeTab === 'dashboard' ? 'active' : ''} onClick={() => setActiveTab('dashboard')}>
          Дашборд
        </button>
        <button className={activeTab === 'users' ? 'active' : ''} onClick={() => setActiveTab('users')}>
          Пользователи
        </button>
        <button className={activeTab === 'properties' ? 'active' : ''} onClick={() => setActiveTab('properties')}>
          Модерация
        </button>
      </div>

      {loading ? (
        <div className="loading">Загрузка...</div>
      ) : (
        <>
          {activeTab === 'dashboard' && (
            <div className="dashboard-stats">
              <div className="stat-card">
                <h3>Пользователи</h3>
                <p className="stat-number">{stats.users}</p>
              </div>
              <div className="stat-card">
                <h3>Объявления</h3>
                <p className="stat-number">{stats.properties}</p>
              </div>
              <div className="stat-card">
                <h3>На модерации</h3>
                <p className="stat-number">{stats.pending}</p>
              </div>
              <div className="stat-card">
                <h3>Активные</h3>
                <p className="stat-number">{stats.active}</p>
              </div>
            </div>
          )}

          {activeTab === 'users' && (
            <div className="users-table-container">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Имя</th>
                    <th>Email</th>
                    <th>Телефон</th>
                    <th>Роль</th>
                    <th>Статус</th>
                    <th>Действия</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(user => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      <td>{user.username}</td>
                      <td>{user.email}</td>
                      <td>{user.phone}</td>
                      <td>{user.role}</td>
                      <td>{user.is_blocked ? 'Заблокирован' : 'Активен'}</td>
                      <td>
                        <button 
                          className={user.is_blocked ? 'unblock-btn' : 'block-btn'}
                          onClick={() => handleBlockUser(user.id, user.is_blocked)}
                        >
                          {user.is_blocked ? 'Разблокировать' : 'Заблокировать'}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {activeTab === 'properties' && (
            <div className="properties-table-container">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Название</th>
                    <th>Цена</th>
                    <th>Владелец</th>
                    <th>Статус</th>
                    <th>Действия</th>
                  </tr>
                </thead>
                <tbody>
                  {properties.map(property => (
                    <tr key={property.id}>
                      <td>{property.id}</td>
                      <td>{property.title}</td>
                      <td>{property.price.toLocaleString()} ₽</td>
                      <td>{property.owner_name}</td>
                      <td>
                        <span className={`status-badge status-${property.status}`}>
                          {property.status === 'pending' ? 'На модерации' : 
                           property.status === 'active' ? 'Активно' : 'Отклонено'}
                        </span>
                      </td>
                      <td>
                        {property.status === 'pending' && (
                          <>
                            <button className="approve-btn" onClick={() => handleApprove(property.id)}>
                              Одобрить
                            </button>
                            <button className="reject-btn" onClick={() => handleReject(property.id)}>
                              Отклонить
                            </button>
                          </>
                        )}
                        <button className="delete-btn" onClick={() => handleDeleteProperty(property.id)}>
                          Удалить
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default AdminPage;
